@app.route('/slow-operation')
def slow_operation():
    """Simulates a slow operation to demonstrate span duration."""
    app_logger.info("Initiating a simulated slow operation...")
    time.sleep(0.5)  # Simulate some processing time
    app_logger.info("Simulated slow operation completed.")
    return jsonify(message="Operation completed after 500ms.")

@app.route('/users', methods=['GET', 'POST'])
def handle_users():
    """
    Handles user creation (POST) and listing (GET).
    Demonstrates SQL query capture.
    """
    session = Session()
    try:
        if request.method == 'POST':
            data = request.json
            if not data or 'username' not in data or 'email' not in data:
                return jsonify(error="Username and email are required in JSON body."), 400

            app_logger.info(f"Attempting to add new user: {data['username']}")
            new_user = User(username=data['username'], email=data['email'])
            session.add(new_user)
            session.commit() # This commit will trigger a database write
            app_logger.info(f"User '{new_user.username}' added successfully.")
            return jsonify(message="User added successfully", user={"id": new_user.id, "username": new_user.username}), 201
        else:  # GET request
            app_logger.info("Fetching all users from the database.")
            users = session.query(User).all() # This query will be captured
            users_data = [{"id": u.id, "username": u.username, "email": u.email} for u in users]
            app_logger.info(f"Found {len(users_data)} users.")
            return jsonify(users_data)
    except Exception as e:
        session.rollback() # Rollback in case of error
        capture_exception() # Manually capture the exception with APM
        app_logger.error(f"Error handling users: {e}", exc_info=True)
        return jsonify(error=f"An error occurred: {str(e)}"), 500
    finally:
        session.close() # Ensure session is closed

