@app.route('/capture-manual-exception')
def capture_manual_exception():
    """
    Triggers an exception and demonstrates how to manually capture it
    without re-raising it, allowing the application to continue.
    """
    try:
        app_logger.warning("Attempting a division by zero to trigger an exception.")
        result = 1 / 0
        app_logger.info(f"Result: {result}") # This line will not be reached
    except Exception:
        # Manually capture the exception with APM.
        # This sends the exception details and stack trace to the APM server.
        capture_exception()
        app_logger.error("A division by zero error occurred and was manually captured.", exc_info=True)
        return jsonify(message="Exception occurred and was manually captured. Check APM for details."), 200

@app.route('/custom-span')
def custom_span():
    """
    Demonstrates creating a custom span within a transaction.
    Useful for monitoring specific internal logic or third-party calls.
    """
    app_logger.info("Starting custom span demonstration.")
    # Get the current APM client instance
    apm_client = client.get_client()
    if apm_client:
        # Create a custom span named 'my_custom_processing' with type 'app.internal'
        with apm_client.begin_span('my_custom_processing', 'app.internal') as span:
            app_logger.info("Executing custom processing step 1...")
            time.sleep(0.1)
            # Add a label to the span for more context
            span.label('step_name', 'initialization')
            app_logger.info("Executing custom processing step 2...")
            time.sleep(0.05)
            span.label('status', 'complete')
    else:
        app_logger.warning("APM client not available, skipping custom span creation.")

    app_logger.info("Custom span demonstration finished.")
    return jsonify(message="Custom span recorded (if APM is enabled and client available).")

